(function(){
	function QR8bitByte(data){this.mode=1;this.data=data;}
	QR8bitByte.prototype={getLength:function(){return this.data.length;},write:function(buffer){for(var i=0;i<this.data.length;i++){buffer.put(this.data.charCodeAt(i),8);}}};
	function QRBitBuffer(){this.buffer=[];this.length=0;}
	QRBitBuffer.prototype={get:function(i){var bufIndex=Math.floor(i/8);return ((this.buffer[bufIndex]>>> (7-i%8))&1)==1;},put:function(num,length){for(var i=0;i<length;i++){this.putBit(((num>>> (length-i-1))&1)==1);}},getLengthInBits:function(){return this.length;},putBit:function(bit){var bufIndex=Math.floor(this.length/8);if(this.buffer.length<=bufIndex){this.buffer.push(0);}if(bit){this.buffer[bufIndex]|=(0x80>>> (this.length%8));}this.length++;}};
	var QRCodeModel=function(typeNumber,errorCorrectLevel){this.typeNumber=typeNumber;this.errorCorrectLevel=errorCorrectLevel;this.modules=null;this.moduleCount=0;this.dataCache=null;this.dataList=[];};
	QRCodeModel.prototype={addData:function(data){this.dataList.push(new QR8bitByte(data));this.dataCache=null;},isDark:function(row,col){if(row<0||this.moduleCount<=row||col<0||this.moduleCount<=col){throw new Error(row+","+col);}return this.modules[row][col];},getModuleCount:function(){return this.moduleCount;},make:function(){this.typeNumber=4;this.makeImpl(false,0);},makeImpl:function(test,maskPattern){this.moduleCount=4*this.typeNumber+17;this.modules=new Array(this.moduleCount);for(var row=0;row<this.moduleCount;row++){this.modules[row]=new Array(this.moduleCount);for(var col=0;col<this.moduleCount;col++){this.modules[row][col]=null;}}
		this.setupPositionProbePattern(0,0);this.setupPositionProbePattern(this.moduleCount-7,0);this.setupPositionProbePattern(0,this.moduleCount-7);this.setupTimingPattern();
		this.dataCache=this.createData();this.mapData(this.dataCache,maskPattern);},setupPositionProbePattern:function(row,col){for(var r=-1;r<=7;r++){if(row+r<=-1||this.moduleCount<=row+r)continue;for(var c=-1;c<=7;c++){if(col+c<=-1||this.moduleCount<=col+c)continue;this.modules[row+r][col+c]=(0<=r&&r<=6&&(c==0||c==6)||0<=c&&c<=6&&(r==0||r==6)||2<=r&&r<=4&&2<=c&&c<=4);}}},setupTimingPattern:function(){for(var i=8;i<this.moduleCount-8;i++){if(this.modules[i][6]==null)this.modules[i][6]=(i%2==0);if(this.modules[6][i]==null)this.modules[6][i]=(i%2==0);}},createData:function(){var buffer=new QRBitBuffer();for(var i=0;i<this.dataList.length;i++){var data=this.dataList[i];buffer.put(1,4);buffer.put(data.getLength(),8);data.write(buffer);}buffer.put(0,4);while(buffer.getLengthInBits()%8!=0)buffer.putBit(false);return buffer.buffer;},mapData:function(data,maskPattern){var inc=-1;var row=this.moduleCount-1;var bitIndex=7;var byteIndex=0;for(var col=this.moduleCount-1;col>0;col-=2){if(col==6)col--;while(true){for(var c=0;c<2;c++){if(this.modules[row][col-c]==null){var dark=false;if(byteIndex<data.length){dark=((data[byteIndex]>>>bitIndex)&1)==1;}var mask=((row+col-c)%2==0);this.modules[row][col-c]=(mask? !dark: dark);bitIndex--;if(bitIndex==-1){byteIndex++;bitIndex=7;}}}
			row+=inc;if(row<0||this.moduleCount<=row){row-=inc;inc=-inc;break;}}
		}
	}
	};

	function QRCode(el,options){this._el=el;this._options=options||{};this._options.text=this._options.text||"";this._options.width=this._options.width||128;this._options.height=this._options.height||128;this.makeCode(this._options.text);}
	QRCode.CorrectLevel={L:1,M:0,Q:3,H:2};
	QRCode.prototype={makeCode:function(text){while(this._el.firstChild)this._el.removeChild(this._el.firstChild);var model=new QRCodeModel(4,QRCode.CorrectLevel.M);model.addData(text);model.make();var count=model.getModuleCount();var canvas=document.createElement('canvas');canvas.width=this._options.width;canvas.height=this._options.height;var ctx=canvas.getContext('2d');var tileW=this._options.width/count;var tileH=this._options.height/count;for(var row=0;row<count;row++){for(var col=0;col<count;col++){ctx.fillStyle=model.isDark(row,col)?'#000':'#fff';var w=Math.ceil((col+1)*tileW)-Math.floor(col*tileW);var h=Math.ceil((row+1)*tileH)-Math.floor(row*tileH);ctx.fillRect(Math.round(col*tileW),Math.round(row*tileH),w,h);}}
		this._el.appendChild(canvas);
	}};
	window.QRCode=QRCode;
})();
